sql:
SELECT 
    COUNT(student_id) AS total_students_enrolled
FROM enrollments;

SELECT COUNT(DISTINCT student_id) AS total_enrolled_students
FROM enrollments
WHERE status = 'enrolled';

external_knowledge:
- 'Unique students' refers to distinct students who have enrolled in courses within the department;
- 'Total enrollments' refers to the cumulative number of enrollments across all courses in the department;
- 'Course offerings' refers to the number of distinct courses offered by the department in each semester.

- 'Graduates of the academic spring blossoms' refers to students in their final year of study during the Spring 2023 semester;
- 'Not let any storm of failure or withdrawal cloud their journey' means students who have not received an 'F' (Fail) or 'W' (Withdraw) grade in any of their courses;
- 'Blossomed in more than three different courses' means students who have enrolled in more than three distinct courses.

- 'stars' refers to students who have received an 'A' as their final grade;
- 'highest honors' refers to the final grade 'A';
- 'midpoint of their academic journey' refers to the average year of study across all students.

- "blossoming students" refers to students who are active;
- "planted their roots in the same soil as their courses" means students who have enrolled in courses offered by their own department;
- "thrive" indicates that both the student and the course are active.

sql:
SELECT AVG(student_count) AS average_students_per_offering
FROM (
    SELECT offering_id, COUNT(student_id) AS student_count
    FROM enrollments
    GROUP BY offering_id
) AS student_counts;

external_knowledge:
- Courses with prerequisites typically require students to complete certain other courses before enrolling;
- The Fall semester refers to the academic term starting in August or September and ending in December or January;
- An open course with available seats means the course is currently accepting new enrollments and has not reached its maximum capacity.

- 'elite trio' refers to the top 3 courses;
- 'command the most hours in the lecture hall' refers to having the highest theory hours;
- 'in each department' means the results are department-specific.

- "blossomed with at least one course offering in the Fall semester" means that the department has at least one course offered in the Fall semester;
- "average enrollment" is the total enrollment divided by the number of course offerings;
- "overall average enrollment" is the average of the average enrollments across all qualifying departments.

- "enrolled" status indicates that a student is currently taking the course;
- "Fall 2023" refers to the academic semester and year;
- "more than 10 students" implies a minimum threshold for the count of enrolled students.

- "Blossoming sophomores" refers to students in their second year of study;
- "Surpassed the GPA threshold of 3.5" means students with a GPA greater than 3.5;
- "Nurturing more than one required course" means students are enrolled in more than one required course.

- "Total hours of courses" refers to the sum of theory and practice hours for all courses offered in a department;
- "Average GPA of students" is the mean grade point average of students in each department;
- "Number of course offerings" is the count of distinct course offerings in each department;
- "Number of students enrolled" is the count of distinct students enrolled in courses within each department.

sql:
SELECT MAX(course_count) AS highest_course_count
FROM (
  SELECT department_id, COUNT(offering_id) AS course_count
  FROM course_offerings
  GROUP BY department_id
) AS department_offers;

